/// <summary>
/// Represents an individual person or user in the system.
/// </summary>
[Description("Represents an individual person or user in the system.")]
public record Person
{
    [Key]
    [Description("Unique identifier for the person")]
    public string Id { get; init; } = string.Empty;

    [Required]
    [Description("Full name of the person")]
    public string Name { get; init; } = string.Empty;

    [Description("Email address for contact")]
    public string? Email { get; init; }

    [Description("URL or data URI for profile picture")]
    public string? Avatar { get; init; }

    [Description("Short biography or description")]
    public string? Bio { get; init; }

    [Description("Job title or role within the organization")]
    public string? Role { get; init; }

    [Description("Icon name for visual representation")]
    public string Icon { get; init; } = "Person";

    [Description("Timestamp when the person was created")]
    public DateTimeOffset CreatedAt { get; init; } = DateTimeOffset.UtcNow;

    [Description("Timestamp of last activity")]
    public DateTimeOffset? LastActiveAt { get; init; }
}
